// layout: float3 pos, float2 uv, uint32 color, uint32 normal, uint32 tex2 = 32 bytes
static bgfx::VertexLayout s_standardLayout;
static bool s_layoutInitialized = false;

static void InitVertexLayouts()
{
	if (s_layoutInitialized) return;
	s_standardLayout
		.begin()
		.add(bgfx::Attrib::Position, 3, bgfx::AttribType::Float)
		.add(bgfx::Attrib::TexCoord0, 2, bgfx::AttribType::Float)
		.add(bgfx::Attrib::Color0, 4, bgfx::AttribType::Uint8, true)
		.add(bgfx::Attrib::Normal, 4, bgfx::AttribType::Uint8, true)
		.add(bgfx::Attrib::TexCoord1, 4, bgfx::AttribType::Uint8, true)
		.end();
	s_layoutInitialized = true;
}

bool BgfxRenderer::Init(SDLWindow& window, int width, int height)
{
	m_width = width;
	m_height = height;

	bgfx::renderFrame();

	bgfx::Init init;
	init.type = bgfx::RendererType::Count;
	init.resolution.width = width;
	init.resolution.height = height;
	init.resolution.reset = BGFX_RESET_VSYNC;
	init.platformData.nwh = window.GetNativeWindowHandle();
	init.platformData.ndt = window.GetNativeDisplayHandle();

	if (!bgfx::init(init))
		return false;

	bgfx::setViewClear(0, BGFX_CLEAR_COLOR | BGFX_CLEAR_DEPTH, 0x1a1a2eff, 1.0f, 0);
	bgfx::setViewRect(0, 0, 0, (uint16_t)width, (uint16_t)height);

	for (int i = 0; i < STACK_DEPTH; i++)
	{
		bx::mtxIdentity(m_modelViewStack[i]);
		bx::mtxIdentity(m_projectionStack[i]);
	}
	bx::mtxIdentity(m_textureMatrix);

	m_mvTop = 0;
	m_projTop = 0;
	m_currentMode = 0;

	memset(m_texSlots, 0, sizeof(m_texSlots));
	for (int i = 0; i < MAX_TEXTURES; i++)
		m_texSlots[i].bgfxHandle = 0xFFFF;

	m_texColorUniform = bgfx::createUniform("s_texColor", bgfx::UniformType::Sampler).idx;

	// 1x1 white fallback texture for untextured draws
	{
		uint32_t white = 0xFFFFFFFF;
		const bgfx::Memory* mem = bgfx::copy(&white, 4);
		bgfx::TextureHandle th = bgfx::createTexture2D(1, 1, false, 1, bgfx::TextureFormat::RGBA8, 0, mem);
		m_whiteTexture = th.idx;
	}

	InitVertexLayouts();
	LoadShaders();

	return true;
}

void BgfxRenderer::LoadShaders()
{
	if (m_shadersLoaded) return;

	const uint8_t* vsData = nullptr;
	uint32_t vsSize = 0;
	const uint8_t* fsData = nullptr;
	uint32_t fsSize = 0;

	bgfx::RendererType::Enum type = bgfx::getRendererType();
	switch (type)
	{
	case bgfx::RendererType::Direct3D11:
	case bgfx::RendererType::Direct3D12:
		vsData = vs_minecraft_d3d11; vsSize = sizeof(vs_minecraft_d3d11);
		fsData = fs_minecraft_d3d11; fsSize = sizeof(fs_minecraft_d3d11);
		break;
	case bgfx::RendererType::OpenGL:
	case bgfx::RendererType::OpenGLES:
		vsData = vs_minecraft_glsl; vsSize = sizeof(vs_minecraft_glsl);
		fsData = fs_minecraft_glsl; fsSize = sizeof(fs_minecraft_glsl);
		break;
	case bgfx::RendererType::Metal:
#ifdef MINECRAFT_HAS_METAL_SHADERS
		vsData = vs_minecraft_mtl; vsSize = sizeof(vs_minecraft_mtl);
		fsData = fs_minecraft_mtl; fsSize = sizeof(fs_minecraft_mtl);
		break;
#endif
		[[fallthrough]];
	default:
		vsData = vs_minecraft_d3d11; vsSize = sizeof(vs_minecraft_d3d11);
		fsData = fs_minecraft_d3d11; fsSize = sizeof(fs_minecraft_d3d11);
		break;
	}

	bgfx::ShaderHandle vsh = bgfx::createShader(bgfx::copy(vsData, vsSize));
	bgfx::ShaderHandle fsh = bgfx::createShader(bgfx::copy(fsData, fsSize));
	m_program = bgfx::createProgram(vsh, fsh, true).idx;
	m_shadersLoaded = true;
}

void BgfxRenderer::Shutdown()
{
	bgfx::ProgramHandle prog = { m_program };
	if (bgfx::isValid(prog))
		bgfx::destroy(prog);
	m_program = 0xFFFF;

	bgfx::UniformHandle uh = { m_texColorUniform };
	if (bgfx::isValid(uh))
		bgfx::destroy(uh);

	for (int i = 0; i < MAX_TEXTURES; i++)
	{
		if (m_texSlots[i].used)
		{
			bgfx::TextureHandle th = { m_texSlots[i].bgfxHandle };
			if (bgfx::isValid(th))
				bgfx::destroy(th);
			m_texSlots[i].used = false;
		}
	}

	bgfx::shutdown();
}

void BgfxRenderer::Resize(int width, int height)
{
	m_width = width;
	m_height = height;
	bgfx::reset((uint32_t)width, (uint32_t)height, BGFX_RESET_VSYNC);
	bgfx::setViewRect(0, 0, 0, (uint16_t)width, (uint16_t)height);
}

