void BgfxRenderer::Clear(int flags, void*)
{
	uint32_t rgba =
		((uint32_t)(m_clearColor[0] * 255) << 24) |
		((uint32_t)(m_clearColor[1] * 255) << 16) |
		((uint32_t)(m_clearColor[2] * 255) << 8) |
		((uint32_t)(m_clearColor[3] * 255));

	uint16_t clearFlags = 0;
	if (flags & 2) clearFlags |= BGFX_CLEAR_COLOR;
	if (flags & 1) clearFlags |= BGFX_CLEAR_DEPTH;

	bgfx::setViewClear(0, clearFlags, rgba, 1.0f, 0);
}

void BgfxRenderer::SetClearColour(const float rgba[4])
{
	memcpy(m_clearColor, rgba, sizeof(float) * 4);
}

