float* BgfxRenderer::GetCurrentMatrix()
{
	switch (m_currentMode)
	{
	case 0: return m_modelViewStack[m_mvTop];
	case 1: return m_projectionStack[m_projTop];
	case 2: return m_textureMatrix;
	default: return m_modelViewStack[m_mvTop];
	}
}

void BgfxRenderer::MatrixSetIdentity()
{
	bx::mtxIdentity(GetCurrentMatrix());
}

void BgfxRenderer::MatrixTranslate(float x, float y, float z)
{
	float tmp[16];
	bx::mtxTranslate(tmp, x, y, z);
	float* cur = GetCurrentMatrix();
	float result[16];
	bx::mtxMul(result, cur, tmp);
	memcpy(cur, result, sizeof(float) * 16);
}

void BgfxRenderer::MatrixRotate(float angle, float x, float y, float z)
{
	// angle is already in radians (glWrapper converts degrees→radians before calling)
	float rad = angle;
	float tmp[16];

	if (x == 0.0f && y == 0.0f && z != 0.0f)
		bx::mtxRotateZ(tmp, z > 0 ? rad : -rad);
	else if (x == 0.0f && y != 0.0f && z == 0.0f)
		bx::mtxRotateY(tmp, y > 0 ? rad : -rad);
	else if (x != 0.0f && y == 0.0f && z == 0.0f)
		bx::mtxRotateX(tmp, x > 0 ? rad : -rad);
	else
	{
		float len = bx::sqrt(x*x + y*y + z*z);
		if (len < 1e-6f) return;
		float nx = x/len, ny = y/len, nz = z/len;
		float c = bx::cos(rad), s = bx::sin(rad), t = 1.0f - c;
		tmp[ 0] = t*nx*nx + c;    tmp[ 1] = t*nx*ny + s*nz; tmp[ 2] = t*nx*nz - s*ny; tmp[ 3] = 0.0f;
		tmp[ 4] = t*nx*ny - s*nz; tmp[ 5] = t*ny*ny + c;    tmp[ 6] = t*ny*nz + s*nx; tmp[ 7] = 0.0f;
		tmp[ 8] = t*nx*nz + s*ny; tmp[ 9] = t*ny*nz - s*nx; tmp[10] = t*nz*nz + c;    tmp[11] = 0.0f;
		tmp[12] = 0.0f;           tmp[13] = 0.0f;            tmp[14] = 0.0f;            tmp[15] = 1.0f;
	}

	float* cur = GetCurrentMatrix();
	float result[16];
	bx::mtxMul(result, cur, tmp);
	memcpy(cur, result, sizeof(float) * 16);
}

void BgfxRenderer::MatrixScale(float x, float y, float z)
{
	float tmp[16];
	bx::mtxScale(tmp, x, y, z);
	float* cur = GetCurrentMatrix();
	float result[16];
	bx::mtxMul(result, cur, tmp);
	memcpy(cur, result, sizeof(float) * 16);
}

void BgfxRenderer::MatrixPerspective(float fovy, float aspect, float zNear, float zFar)
{
	float* cur = GetCurrentMatrix();
	bx::mtxProj(cur, fovy, aspect, zNear, zFar, bgfx::getCaps()->homogeneousDepth);
}

void BgfxRenderer::MatrixOrthogonal(float left, float right, float bottom, float top, float zNear, float zFar)
{
	float* cur = GetCurrentMatrix();
	bx::mtxOrtho(cur, left, right, bottom, top, zNear, zFar, 0.0f, bgfx::getCaps()->homogeneousDepth);
}

void BgfxRenderer::MatrixPush()
{
	if (m_currentMode == 0 && m_mvTop < STACK_DEPTH - 1)
	{
		memcpy(m_modelViewStack[m_mvTop + 1], m_modelViewStack[m_mvTop], sizeof(float) * 16);
		m_mvTop++;
	}
	else if (m_currentMode == 1 && m_projTop < STACK_DEPTH - 1)
	{
		memcpy(m_projectionStack[m_projTop + 1], m_projectionStack[m_projTop], sizeof(float) * 16);
		m_projTop++;
	}
}

void BgfxRenderer::MatrixPop()
{
	if (m_currentMode == 0 && m_mvTop > 0)
		m_mvTop--;
	else if (m_currentMode == 1 && m_projTop > 0)
		m_projTop--;
}

void BgfxRenderer::MatrixMult(float* mat)
{
	float* cur = GetCurrentMatrix();
	float result[16];
	bx::mtxMul(result, cur, mat);
	memcpy(cur, result, sizeof(float) * 16);
}

const float* BgfxRenderer::MatrixGet(int type)
{
	switch (type)
	{
	case 0: return m_modelViewStack[m_mvTop];
	case 1: return m_projectionStack[m_projTop];
	case 2: return m_textureMatrix;
	default: return m_modelViewStack[m_mvTop];
	}
}

void BgfxRenderer::Set_matrixDirty() {}

// GL blend factor enum → bgfx blend constant
static uint64_t GLBlendToBgfx(int glFactor)
{
	switch (glFactor)
	{
	case 1:  return BGFX_STATE_BLEND_ZERO;           // GL_ZERO
	case 2:  return BGFX_STATE_BLEND_ONE;            // GL_ONE
	case 3:  return BGFX_STATE_BLEND_SRC_COLOR;      // GL_SRC_COLOR
	case 4:  return BGFX_STATE_BLEND_INV_SRC_COLOR;  // GL_ONE_MINUS_SRC_COLOR
	case 5:  return BGFX_STATE_BLEND_SRC_ALPHA;      // GL_SRC_ALPHA
	case 6:  return BGFX_STATE_BLEND_INV_SRC_ALPHA;  // GL_ONE_MINUS_SRC_ALPHA
	case 7:  return BGFX_STATE_BLEND_DST_ALPHA;      // GL_DST_ALPHA
	case 9:  return BGFX_STATE_BLEND_DST_COLOR;      // GL_DST_COLOR
	case 10: return BGFX_STATE_BLEND_INV_DST_COLOR;  // GL_ONE_MINUS_DST_COLOR
	default: return BGFX_STATE_BLEND_ONE;
	}
}

uint64_t BgfxRenderer::BuildBgfxState() const
{
	uint64_t state = BGFX_STATE_WRITE_RGB | BGFX_STATE_WRITE_A;

	if (m_depthTestEnabled)
	{
		switch (m_depthFunc)
		{
		case 4:  state |= BGFX_STATE_DEPTH_TEST_LEQUAL; break;  // GL_LEQUAL
		case 5:  state |= BGFX_STATE_DEPTH_TEST_GREATER; break; // GL_GREATER
		case 3:  state |= BGFX_STATE_DEPTH_TEST_EQUAL; break;   // GL_EQUAL
		case 7:  state |= BGFX_STATE_DEPTH_TEST_GEQUAL; break;  // GL_GEQUAL
		case 8:  state |= BGFX_STATE_DEPTH_TEST_ALWAYS; break;  // GL_ALWAYS
		default: state |= BGFX_STATE_DEPTH_TEST_LESS; break;
		}
	}

	if (m_depthWriteEnabled)
		state |= BGFX_STATE_WRITE_Z;

	if (m_blendEnabled)
		state |= BGFX_STATE_BLEND_FUNC(GLBlendToBgfx(m_blendSrc), GLBlendToBgfx(m_blendDst));

	if (m_cullEnabled)
		state |= m_cullCW ? BGFX_STATE_CULL_CW : BGFX_STATE_CULL_CCW;

	if (m_alphaTestEnabled && m_alphaRef > 0.0f)
		state |= BGFX_STATE_BLEND_ALPHA_TO_COVERAGE;

	return state;
}

void BgfxRenderer::ConvertQuadsToTriangles(const void* quadData, int quadVertCount, int vertexStride, void* triOut, int& triVertCount) const
{
	// every 4 vertices (quad) → 6 vertices (2 triangles): (v0,v1,v2), (v0,v2,v3)
	int numQuads = quadVertCount / 4;
	triVertCount = numQuads * 6;
	const uint8_t* src = (const uint8_t*)quadData;
	uint8_t* dst = (uint8_t*)triOut;

	for (int q = 0; q < numQuads; q++)
	{
		const uint8_t* v0 = src + (q * 4 + 0) * vertexStride;
		const uint8_t* v1 = src + (q * 4 + 1) * vertexStride;
		const uint8_t* v2 = src + (q * 4 + 2) * vertexStride;
		const uint8_t* v3 = src + (q * 4 + 3) * vertexStride;

		memcpy(dst, v0, vertexStride); dst += vertexStride;
		memcpy(dst, v1, vertexStride); dst += vertexStride;
		memcpy(dst, v2, vertexStride); dst += vertexStride;
		memcpy(dst, v0, vertexStride); dst += vertexStride;
		memcpy(dst, v2, vertexStride); dst += vertexStride;
		memcpy(dst, v3, vertexStride); dst += vertexStride;
	}
}

void BgfxRenderer::SubmitDraw(ePrimitiveType primType, int count, void* dataIn, eVertexType vType,
							  int texIdx, float mvMatrix[16], float projMatrix[16])
{
	if (!m_shadersLoaded || count <= 0 || !dataIn)
		return;

	if (vType == VERTEX_TYPE_COMPRESSED)
		return;

	const int vertexStride = 32;
	int drawVertCount = count;
	uint8_t* vertexData = nullptr;

	if (primType == PRIMITIVE_TYPE_QUAD_LIST)
	{
		int triVertCount = 0;
		int numQuads = count / 4;
		vertexData = new uint8_t[numQuads * 6 * vertexStride];
		ConvertQuadsToTriangles(dataIn, count, vertexStride, vertexData, triVertCount);
		drawVertCount = triVertCount;
		primType = PRIMITIVE_TYPE_TRIANGLE_LIST;
	}
	else if (primType == PRIMITIVE_TYPE_TRIANGLE_FAN && count >= 3)
	{
		// fan (v0,v1,...,vN) → triangles (v0,v1,v2), (v0,v2,v3), ..., (v0,vN-1,vN)
		int numTris = count - 2;
		drawVertCount = numTris * 3;
		vertexData = new uint8_t[drawVertCount * vertexStride];
		const uint8_t* src = (const uint8_t*)dataIn;
		uint8_t* dst = vertexData;
		for (int t = 0; t < numTris; t++)
		{
			memcpy(dst, src, vertexStride); dst += vertexStride; // v0
			memcpy(dst, src + (t + 1) * vertexStride, vertexStride); dst += vertexStride;
			memcpy(dst, src + (t + 2) * vertexStride, vertexStride); dst += vertexStride;
		}
		primType = PRIMITIVE_TYPE_TRIANGLE_LIST;
	}
	else
	{
		vertexData = new uint8_t[count * vertexStride];
		memcpy(vertexData, dataIn, count * vertexStride);
		drawVertCount = count;
	}

	// color at offset 20: game stores (R<<24|G<<16|B<<8|A), need [R,G,B,A] bytes for bgfx
	for (int i = 0; i < drawVertCount; i++)
	{
		uint8_t* c = vertexData + i * vertexStride + 20;
		uint8_t a = c[0], b = c[1], g = c[2], r = c[3];
		c[0] = r; c[1] = g; c[2] = b; c[3] = a;
	}

	bgfx::TransientVertexBuffer tvb;
	if (!bgfx::getAvailTransientVertexBuffer(drawVertCount, s_standardLayout))
	{
		delete[] vertexData;
		return;
	}
	bgfx::allocTransientVertexBuffer(&tvb, drawVertCount, s_standardLayout);
	memcpy(tvb.data, vertexData, drawVertCount * vertexStride);
	delete[] vertexData;

	bgfx::setVertexBuffer(0, &tvb);

	// white fallback if no texture bound
	{
		bgfx::UniformHandle uh = { m_texColorUniform };
		bgfx::TextureHandle th = { m_whiteTexture };
		if (texIdx >= 0 && texIdx < MAX_TEXTURES && m_texSlots[texIdx].used)
		{
			bgfx::TextureHandle texHandle = { m_texSlots[texIdx].bgfxHandle };
			if (bgfx::isValid(texHandle))
				th = texHandle;
		}
		if (bgfx::isValid(th) && bgfx::isValid(uh))
			bgfx::setTexture(0, uh, th);
	}

	float mvp[16];
	bx::mtxMul(mvp, mvMatrix, projMatrix);
	bgfx::setTransform(mvp);

	uint64_t state = BuildBgfxState();
	switch (primType)
	{
	case PRIMITIVE_TYPE_TRIANGLE_STRIP: state |= BGFX_STATE_PT_TRISTRIP; break;
	case PRIMITIVE_TYPE_LINE_LIST:      state |= BGFX_STATE_PT_LINES;    break;
	case PRIMITIVE_TYPE_LINE_STRIP:     state |= BGFX_STATE_PT_LINESTRIP; break;
	default: break;
	}
	bgfx::setState(state);

	bgfx::ProgramHandle prog = { m_program };
	bgfx::submit(0, prog);
}

void BgfxRenderer::DrawVertices(ePrimitiveType primType, int count, void* dataIn, eVertexType vType, ePixelShaderType psType)
{
	if (count <= 0 || !dataIn)
		return;

	if (vType == VERTEX_TYPE_COMPRESSED)
		return;

	const int vertexStride = 32;

	if (m_recordingBuffer >= 0 && m_cmdBuffers)
	{
		CmdBuffer& cb = m_cmdBuffers[m_recordingBuffer];
		RecordedDraw draw;
		draw.primType = primType;
		draw.vType = vType;
		draw.vertCount = count;
		draw.texIdx = m_boundTexture;
		memcpy(draw.mvMatrix, m_modelViewStack[m_mvTop], 64);
		memcpy(draw.projMatrix, m_projectionStack[m_projTop], 64);
		draw.blendEnabled = m_blendEnabled;
		draw.blendSrc = m_blendSrc;
		draw.blendDst = m_blendDst;
		draw.depthTestEnabled = m_depthTestEnabled;
		draw.depthWriteEnabled = m_depthWriteEnabled;
		draw.depthFunc = m_depthFunc;
		draw.cullEnabled = m_cullEnabled;
		draw.cullCW = m_cullCW;
		draw.alphaTestEnabled = m_alphaTestEnabled;
		draw.alphaRef = m_alphaRef;
		int dataSize = count * vertexStride;
		draw.vertexData = new uint8_t[dataSize];
		memcpy(draw.vertexData, dataIn, dataSize);
		cb.AddDraw(draw);
		return;
	}

	SubmitDraw(primType, count, dataIn, vType, m_boundTexture,
			   m_modelViewStack[m_mvTop], m_projectionStack[m_projTop]);
}

void BgfxRenderer::DrawVertexBuffer(ePrimitiveType primType, int count, void* buffer, eVertexType vType, ePixelShaderType psType)
{
	DrawVertices(primType, count, buffer, vType, psType);
}

void BgfxRenderer::CmdBuffer::Clear()
{
	for (int i = 0; i < drawCount; i++)
		delete[] draws[i].vertexData;
	drawCount = 0;
	totalBytes = 0;
}

void BgfxRenderer::CmdBuffer::AddDraw(const RecordedDraw& draw)
{
	if (drawCount >= drawCapacity)
	{
		int newCap = drawCapacity == 0 ? 64 : drawCapacity * 2;
		RecordedDraw* newDraws = new RecordedDraw[newCap];
		if (draws)
		{
			memcpy(newDraws, draws, drawCount * sizeof(RecordedDraw));
			delete[] draws;
		}
		draws = newDraws;
		drawCapacity = newCap;
	}
	draws[drawCount++] = draw;
	totalBytes += draw.vertCount * 32 + sizeof(RecordedDraw);
}

BgfxRenderer::CmdBuffer::~CmdBuffer()
{
	Clear();
	delete[] draws;
}

void BgfxRenderer::EnsureCmdBuffers()
{
	if (!m_cmdBuffers)
	{
		m_cmdBuffers = new CmdBuffer[MAX_CMD_BUFFERS];
	}
}

void BgfxRenderer::CBuffLockStaticCreations() {}

int BgfxRenderer::CBuffCreate(int count)
{
	EnsureCmdBuffers();
	int first = m_nextCmdBufferId;

	for (int start = 1; start < MAX_CMD_BUFFERS - count; start++)
	{
		bool ok = true;
		for (int i = 0; i < count; i++)
		{
			if (m_cmdBuffers[start + i].allocated)
			{
				ok = false;
				break;
			}
		}
		if (ok)
		{
			for (int i = 0; i < count; i++)
				m_cmdBuffers[start + i].allocated = true;
			if (start + count > m_nextCmdBufferId)
				m_nextCmdBufferId = start + count;
			return start;
		}
	}
	return 0;
}

void BgfxRenderer::CBuffDelete(int first, int count)
{
	if (!m_cmdBuffers) return;
	for (int i = 0; i < count; i++)
	{
		int idx = first + i;
		if (idx > 0 && idx < MAX_CMD_BUFFERS)
		{
			m_cmdBuffers[idx].Clear();
			m_cmdBuffers[idx].allocated = false;
		}
	}
}

void BgfxRenderer::CBuffStart(int index, bool)
{
	EnsureCmdBuffers();
	if (index > 0 && index < MAX_CMD_BUFFERS)
	{
		m_cmdBuffers[index].Clear();
		m_cmdBuffers[index].allocated = true;
		m_recordingBuffer = index;
	}
}

void BgfxRenderer::CBuffClear(int index)
{
	if (!m_cmdBuffers) return;
	if (index > 0 && index < MAX_CMD_BUFFERS)
		m_cmdBuffers[index].Clear();
}

int BgfxRenderer::CBuffSize(int index)
{
	if (!m_cmdBuffers) return 0;
	if (index == -1)
	{
		int total = 0;
		for (int i = 0; i < MAX_CMD_BUFFERS; i++)
			if (m_cmdBuffers[i].allocated)
				total += m_cmdBuffers[i].totalBytes;
		return total;
	}
	if (index > 0 && index < MAX_CMD_BUFFERS)
		return m_cmdBuffers[index].totalBytes;
	return 0;
}

void BgfxRenderer::CBuffEnd()
{
	m_recordingBuffer = -1;
}

bool BgfxRenderer::CBuffCall(int index, bool)
{
	if (!m_cmdBuffers || !m_shadersLoaded) return false;
	if (index <= 0 || index >= MAX_CMD_BUFFERS) return false;

	CmdBuffer& cb = m_cmdBuffers[index];
	if (!cb.allocated || cb.drawCount == 0) return false;

	bool savedBlend = m_blendEnabled;
	int savedBlendSrc = m_blendSrc, savedBlendDst = m_blendDst;
	bool savedDepthTest = m_depthTestEnabled;
	bool savedDepthWrite = m_depthWriteEnabled;
	int savedDepthFunc = m_depthFunc;
	bool savedCull = m_cullEnabled;
	bool savedCullCW = m_cullCW;
	bool savedAlphaTest = m_alphaTestEnabled;
	float savedAlphaRef = m_alphaRef;

	for (int i = 0; i < cb.drawCount; i++)
	{
		RecordedDraw& draw = cb.draws[i];

		m_blendEnabled = draw.blendEnabled;
		m_blendSrc = draw.blendSrc;
		m_blendDst = draw.blendDst;
		m_depthTestEnabled = draw.depthTestEnabled;
		m_depthWriteEnabled = draw.depthWriteEnabled;
		m_depthFunc = draw.depthFunc;
		m_cullEnabled = draw.cullEnabled;
		m_cullCW = draw.cullCW;
		m_alphaTestEnabled = draw.alphaTestEnabled;
		m_alphaRef = draw.alphaRef;

		SubmitDraw(draw.primType, draw.vertCount, draw.vertexData, draw.vType,
				   draw.texIdx, draw.mvMatrix, draw.projMatrix);
	}

	m_blendEnabled = savedBlend;
	m_blendSrc = savedBlendSrc; m_blendDst = savedBlendDst;
	m_depthTestEnabled = savedDepthTest;
	m_depthWriteEnabled = savedDepthWrite;
	m_depthFunc = savedDepthFunc;
	m_cullEnabled = savedCull;
	m_cullCW = savedCullCW;
	m_alphaTestEnabled = savedAlphaTest;
	m_alphaRef = savedAlphaRef;

	return true;
}

