int BgfxRenderer::AllocTextureSlot()
{
	for (int i = 0; i < MAX_TEXTURES; i++)
		if (!m_texSlots[i].used)
		{
			m_texSlots[i].used = true;
			return i;
		}
	return -1;
}

void BgfxRenderer::FreeTextureSlot(int idx)
{
	if (idx >= 0 && idx < MAX_TEXTURES)
	{
		bgfx::TextureHandle th = { m_texSlots[idx].bgfxHandle };
		if (bgfx::isValid(th))
			bgfx::destroy(th);
		m_texSlots[idx] = {};
		m_texSlots[idx].bgfxHandle = 0xFFFF;
	}
}

int BgfxRenderer::TextureCreate()
{
	return AllocTextureSlot();
}

void BgfxRenderer::TextureFree(int idx)
{
	FreeTextureSlot(idx);
}

