// converts ARGB int array → RGBA byte order for bgfx
static const bgfx::Memory* ConvertARGBtoRGBA(const void* data, int width, int height)
{
	if (!data) return nullptr;
	int pixelCount = width * height;
	const bgfx::Memory* mem = bgfx::alloc(pixelCount * 4);
	const uint32_t* src = (const uint32_t*)data;
	uint8_t* dst = mem->data;
	for (int i = 0; i < pixelCount; i++)
	{
		uint32_t argb = src[i];
		dst[i * 4 + 0] = (uint8_t)(argb >> 16); // R
		dst[i * 4 + 1] = (uint8_t)(argb >> 8);  // G
		dst[i * 4 + 2] = (uint8_t)(argb);       // B
		dst[i * 4 + 3] = (uint8_t)(argb >> 24); // A
	}
	return mem;
}

void BgfxRenderer::TextureData(int width, int height, void* data, int level, eTextureFormat)
{
	if (m_boundTexture < 0 || m_boundTexture >= MAX_TEXTURES)
		return;
	TextureSlot& slot = m_texSlots[m_boundTexture];

	if (level == 0)
	{
		bgfx::TextureHandle old = { slot.bgfxHandle };
		if (bgfx::isValid(old))
			bgfx::destroy(old);

		slot.width = width;
		slot.height = height;

		// create without initial data so mip levels can be uploaded via updateTexture2D
		bgfx::TextureHandle th = bgfx::createTexture2D(
			(uint16_t)width, (uint16_t)height,
			m_textureLevels > 1, 1,
			bgfx::TextureFormat::RGBA8,
			BGFX_SAMPLER_U_CLAMP | BGFX_SAMPLER_V_CLAMP,
			nullptr);
		slot.bgfxHandle = th.idx;
	}

	if (data)
	{
		bgfx::TextureHandle th = { slot.bgfxHandle };
		if (bgfx::isValid(th))
		{
			const bgfx::Memory* mem = ConvertARGBtoRGBA(data, width, height);
			bgfx::updateTexture2D(th, 0, (uint8_t)level, 0, 0, (uint16_t)width, (uint16_t)height, mem);
		}
	}
}

void BgfxRenderer::TextureDataUpdate(int xoffset, int yoffset, int width, int height, void* data, int level)
{
	if (m_boundTexture < 0 || m_boundTexture >= MAX_TEXTURES || !data)
		return;
	TextureSlot& slot = m_texSlots[m_boundTexture];
	bgfx::TextureHandle th = { slot.bgfxHandle };
	if (bgfx::isValid(th))
	{
		const bgfx::Memory* mem = ConvertARGBtoRGBA(data, width, height);
		bgfx::updateTexture2D(th, 0, (uint8_t)level,
			(uint16_t)xoffset, (uint16_t)yoffset,
			(uint16_t)width, (uint16_t)height, mem);
	}
}

