long BgfxRenderer::LoadTextureData(const char* szFilename, D3DXIMAGE_INFO* pSrcInfo, int** ppDataOut)
{
	if (!szFilename || !pSrcInfo || !ppDataOut)
		return -1;

	FILE* f = fopen(szFilename, "rb");
	if (!f)
		return -1;

	fseek(f, 0, SEEK_END);
	long fileSize = ftell(f);
	fseek(f, 0, SEEK_SET);

	unsigned char* fileData = new unsigned char[fileSize];
	fread(fileData, 1, fileSize, f);
	fclose(f);

	long result = LoadTextureData(fileData, (unsigned long)fileSize, pSrcInfo, ppDataOut);
	delete[] fileData;
	return result;
}

long BgfxRenderer::LoadTextureData(unsigned char* pbData, unsigned long dwBytes, D3DXIMAGE_INFO* pSrcInfo, int** ppDataOut)
{
	if (!pbData || dwBytes == 0 || !pSrcInfo || !ppDataOut)
		return -1;

	int w = 0, h = 0, channels = 0;
	unsigned char* pixels = stbi_load_from_memory(pbData, (int)dwBytes, &w, &h, &channels, 4);
	if (!pixels)
		return -1;

	pSrcInfo->Width = w;
	pSrcInfo->Height = h;

	// stb returns RGBA bytes; game expects ARGB as int (A<<24|R<<16|G<<8|B)
	int* outData = new int[w * h];
	for (int i = 0; i < w * h; i++)
	{
		unsigned char r = pixels[i * 4 + 0];
		unsigned char g = pixels[i * 4 + 1];
		unsigned char b = pixels[i * 4 + 2];
		unsigned char a = pixels[i * 4 + 3];
		outData[i] = (a << 24) | (r << 16) | (g << 8) | b;
	}

	stbi_image_free(pixels);
	*ppDataOut = outData;
	return 0; // ERROR_SUCCESS
}
